  def install
    libexec.install Dir["*"]

    # Create a wrapper script that invokes the CLI via the system node
    # Requires Node.js >= 18 (nvm, brew node, or system install)
    (bin/"nesbot").write <<~EOS
      #!/usr/bin/env bash
      exec node "#{libexec}/bin/nesbot.js" "$@"
    EOS
  end

  test do
    # Verify the CLI starts and can init a repo
    system bin/"nesbot", "init", "--repo", testpath/"test-repo"
    assert_predicate testpath/"test-repo/.nesbot/config.json", :exist?
  end
end
